import { WardData, MutualActivity, BreadAssignment, LessonAssignment } from './types';
import { mockWardData } from './mockData';

export function formatNormalizedDate(dateStr: string, options?: Intl.DateTimeFormatOptions): string {
  if (!dateStr) return '';
  
  const trimmed = dateStr.trim();
  
  // If it's already a full weekday + month name pattern, e.g. "Wednesday, Jul 8, 2026" or "Sunday, Jul 12, 2026"
  if (/^[A-Za-z]+,\s+[A-Za-z]+\s+\d+,\s+\d{4}$/.test(trimmed)) {
    return trimmed;
  }
  
  try {
    const d = new Date(trimmed);
    if (!isNaN(d.getTime())) {
      const isoDateMatch = trimmed.match(/^(\d{4})-(\d{2})-(\d{2})/);
      let targetDate = d;
      if (isoDateMatch) {
        const year = parseInt(isoDateMatch[1], 10);
        const month = parseInt(isoDateMatch[2], 10) - 1;
        const day = parseInt(isoDateMatch[3], 10);
        targetDate = new Date(year, month, day);
      }
      return targetDate.toLocaleDateString('en-US', options || {
        month: 'short',
        day: 'numeric',
        year: 'numeric'
      });
    }
  } catch (e) {
    // fallback
  }
  return dateStr;
}

export function formatNormalizedTime(timeVal: any): string {
  if (!timeVal) return '7:00 PM';
  const timeStr = String(timeVal).trim();
  if (!timeStr) return '7:00 PM';

  // If it's a standard simple time format already (e.g. "7:00 PM", "6:45 PM", etc.)
  if (/^\d{1,2}:\d{2}\s*(?:AM|PM|am|pm)$/i.test(timeStr)) {
    return timeStr.toUpperCase();
  }

  // Try standard local timezone Date parsing first.
  // Google Sheets stores times as Date objects, which when serialized via Apps Script
  // to ISO strings, are offset by the sheet's timezone.
  // Parsing them in the local browser perfectly restores the local time (e.g., "1899-12-31T01:45:00.000Z" -> "6:45 PM" in Mountain Standard Time / PDT).
  console.log(timeStr)
  try {
    if (timeStr.includes('-') || timeStr.includes('T') || timeStr.includes(':')) {
      const d = new Date(timeStr);
      if (!isNaN(d.getTime())) {
        let hours = d.getHours();
        const minutes = String(d.getMinutes()).padStart(2, '0');
        let ampm = 'AM';
        if (hours >= 12) {
          ampm = 'PM';
          hours = hours % 12;
        } else {
          // For Mutual activities, if the hour is between 1 and 8 (e.g., 6 for 6 PM, 7 for 7 PM),
          // it is almost certainly PM in the event of an offset error or UTC fallback
          if (hours >= 1 && hours <= 8) {
            ampm = 'PM';
          }
        }
        if (hours === 0) hours = 12;
        return `${hours}:${minutes} ${ampm}`;
      }
    }
  } catch (e) {
    // fallback
  }

  // If that fails, let's fall back to parsing the direct characters
  const isoMatch = timeStr.match(/T(\d{1,2}):(\d{2})/);
  if (isoMatch) {
    let hours = parseInt(isoMatch[1], 10);
    const minutes = isoMatch[2];
    let ampm = 'AM';
    if (hours >= 12) {
      ampm = 'PM';
      hours = hours % 12;
    } else {
      if (hours >= 1 && hours <= 8) {
        ampm = 'PM';
      } else {
        ampm = 'AM';
      }
    }
    if (hours === 0) hours = 12;
    return `${hours}:${minutes} ${ampm}`;
  }

  // Handle standard "18:45" or "06:45"
  const hhmmMatch = timeStr.match(/^(\d{1,2}):(\d{2})(?::\d{2})?$/);
  if (hhmmMatch) {
    let hours = parseInt(hhmmMatch[1], 10);
    const minutes = hhmmMatch[2];
    let ampm = 'AM';
    if (hours >= 12) {
      ampm = 'PM';
      hours = hours % 12;
    } else {
      if (hours >= 1 && hours <= 8) {
        ampm = 'PM';
      }
    }
    if (hours === 0) hours = 12;
    return `${hours}:${minutes} ${ampm}`;
  }

  return timeStr;
}

/**
 * Robust normalizer for the incoming JSON from Google Apps Script.
 * Maps variations of keys (e.g. "Mutual activities", "mutual_activities", "Mutual") to standard keys.
 */
export function normalizeWardData(raw: any): WardData {
  if (!raw || typeof raw !== 'object') {
    return mockWardData;
  }

  const result: WardData = {
    mutual: [],
    bread: [],
    lessons: [],
    other: []
  };

  // Find Mutual Activity key
  const mutualKey = Object.keys(raw).find(k => 
    /mutual/i.test(k) || /activity/i.test(k) || /activities/i.test(k)
  );
  if (mutualKey && Array.isArray(raw[mutualKey])) {
    result.mutual = raw[mutualKey].map((item: any) => ({
      date: formatNormalizedDate(item.date || item.Date || item.time || '', { weekday: 'long', month: 'short', day: 'numeric', year: 'numeric' }),
      activity: item.activity || item.Activity || item.description || item.Description || '',
      quorum: (() => {
        const val = item.quorum !== undefined ? item.quorum :
                    item.Quorum !== undefined ? item.Quorum :
                    item.group !== undefined ? item.group :
                    item.Group !== undefined ? item.Group : 'Combined';
        return typeof val === 'boolean' ? (val ? 'true' : 'false') : String(val);
      })(),
      time: formatNormalizedTime(item.time || item.Time),
      location: item.location || item.Location || 'Church',
      details: item.details || item.Details || item.notes || item.Notes || ''
    }));
  }

  // Find Bread Assignment key
  const breadKey = Object.keys(raw).find(k => 
    /bread/i.test(k) || /sacrament/i.test(k)
  );
  if (breadKey && Array.isArray(raw[breadKey])) {
    result.bread = raw[breadKey].map((item: any) => ({
      date: formatNormalizedDate(item.date || item.Date || '', { month: 'short', day: 'numeric', year: 'numeric' }),
      assigned: item.assigned || item.Assigned || item.name || item.Name || '',
      backup: item.backup || item.Backup || item.assistant || item.Assistant || '',
      quorum: item.quorum || item.Quorum || 'Teachers',
      status: item.status || item.Status || 'Assigned'
    }));
  }

  // Find Lesson Assignment key
  const lessonKey = Object.keys(raw).find(k => 
    /lesson/i.test(k) || /class/i.test(k) || /instruction/i.test(k)
  );
  if (lessonKey && Array.isArray(raw[lessonKey])) {
    result.lessons = raw[lessonKey].map((item: any) => ({
      date: formatNormalizedDate(item.date || item.Date || '', { month: 'short', day: 'numeric', year: 'numeric' }),
      topic: item.topic || item.Topic || item.lesson || item.Lesson || 'Sunday Lesson',
      teacher: item.teacher || item.Teacher || item.leader || item.Leader || item.person || item.Person || '',
      quorum: item.quorum || item.Quorum || item.class || item.Class || 'Teachers',
      scripture: item.scripture || item.Scripture || item.reference || item.Reference || ''
    }));
  }

  // Find Other/Additional notes key
  const otherKey = Object.keys(raw).find(k => 
    /other/i.test(k) || /note/i.test(k) || /announcement/i.test(k) || /additional/i.test(k)
  );
  if (otherKey) {
    const val = raw[otherKey];
    if (Array.isArray(val)) {
      result.other = val.map((item: any) => {
        if (typeof item === 'string') return item;
        return item.announcements || item.announcement || item.note || item.text || item.message || (typeof item === 'object' ? Object.values(item)[0] : JSON.stringify(item));
      });
    } else if (typeof val === 'object') {
      result.other = Object.values(val).map((item: any) => {
        if (typeof item === 'string') return item;
        return item.announcements || item.announcement || item.note || item.text || item.message || (typeof item === 'object' ? Object.values(item)[0] : JSON.stringify(item));
      });
    }
  }

  // If we ended up with absolutely empty categories, fill with mock data as fallback
  if (result.mutual.length === 0) result.mutual = mockWardData.mutual;
  if (result.bread.length === 0) result.bread = mockWardData.bread;
  if (result.lessons.length === 0) result.lessons = mockWardData.lessons;
  if (result.other.length === 0) result.other = mockWardData.other;

  return result;
}
